#include <stdio.h
#include <stdlib.h
#include <string.h
#include <unistd.h
#include <sys/types.h>
#include <dirent.h>
#include <time.h>
#include <errno.h>

#define MAX_FILENAME 256
#define MAX_COMMIT_MSG 1024
#define MAX_FILES 100
#define MAX_LINE 2048

typedef struct {
    char name[MAX_FILENAME];
    char hash[9]; // 8 byte hash + null terminator
} FileEntry;

typedef struct {
    char commit_hash[9];
    char prev_commit_hash[9];
    char timestamp[20];
    char message[MAX_COMMIT_MSG];
    FileEntry files[MAX_FILES];
    int file_count;
} Commit;

// Utility functions
void compute_hash(const char *str, char *hash) {
    unsigned long h = 5381;
    int c;
    while ((c = *str++))
        h = ((h << 5) + h) + c;
    snprintf(hash, 9, "%08lx", h);
}

void get_index_path(char *path) {
    snprintf(path, MAX_FILENAME, ".minigit/index");
}

void get_objects_dir(char *path) {
    snprintf(path, MAX_FILENAME, ".minigit/objects");
}

void get_heads_path(char *path) {
    snprintf(path, MAX_FILENAME, ".minigit/refs/heads/master");
}

void get_head_path(char *path) {
    snprintf(path, MAX_FILENAME, ".minigit/HEAD");
}

void get_ref_path(const char *ref, char *path) {
    snprintf(path, MAX_FILENAME, ".minigit/refs/heads/%s", ref);
}

void get_object_path(const char *hash, char *path) {
    char dir[3];
    strncpy(dir, hash, 2);
    dir[2] = '\0';
    snprintf(path, MAX_FILENAME, ".minigit/objects/%s/%s", dir, hash + 2);
}

int file_exists(const char *path) {
    return access(path, F_OK) == 0;
}

void create_dir_if_not_exists(const char *path) {
    char cmd[1024];
    snprintf(cmd, sizeof(cmd), "mkdir -p %s", path);
    system(cmd);
}

void init_repo() {
    system("mkdir -p .minigit/objects .minigit/refs/heads");
    FILE *index = fopen(".minigit/index", "w");
    if (index) fclose(index);
    FILE *head = fopen(".minigit/HEAD", "w");
    if (head) {
        fprintf(head, "ref: refs/heads/master\n");
        fclose(head);
    }
}

void read_index(FileEntry files[], int *count) {
    *count = 0;
    FILE *index = fopen(".minigit/index", "r");
    if (!index) return;
    while (fscanf(index, "%s %s", files[*count].name, files[*count].hash) == 2) {
        (*count)++;
    }
    fclose(index);
}

void write_index(FileEntry files[], int count) {
    FILE *index = fopen(".minigit/index", "w");
    for (int i = 0; i < count; i++) {
        fprintf(index, "%s %s\n", files[i].name, files[i].hash);
    }
    fclose(index);
}

void read_commit(const char *hash, Commit *commit) {
    char path[MAX_FILENAME];
    get_object_path(hash, path);
    FILE *f = fopen(path, "r");
    if (!f) {
        memset(commit, 0, sizeof(Commit));
        return;
    }
    fscanf(f, "%s %s %s\n", commit->commit_hash, commit->prev_commit_hash, commit->timestamp);
    fgets(commit->message, MAX_COMMIT_MSG, f);
    commit->message[strlen(commit->message)-1] = '\0'; // remove newline
    commit->file_count = 0;
    while (fscanf(f, "%s %s", commit->files[commit->file_count].name, commit->files[commit->file_count].hash) == 2) {
        commit->file_count++;
    }
    fclose(f);
}

void write_commit(Commit *commit) {
    char path[MAX_FILENAME];
    get_object_path(commit->commit_hash, path);
    char dir[MAX_FILENAME];
    snprintf(dir, sizeof(dir), ".minigit/objects/%.2s", commit->commit_hash);
    create_dir_if_not_exists(dir);
    FILE *f = fopen(path, "w");
    fprintf(f, "%s %s %s\n", commit->commit_hash, commit->prev_commit_hash, commit->timestamp);
    fprintf(f, "%s\n", commit->message);
    for (int i = 0; i < commit->file_count; i++) {
        fprintf(f, "%s %s\n", commit->files[i].name, commit->files[i].hash);
    }
    fclose(f);
}

char *get_head_ref() {
    static char ref[MAX_FILENAME];
    FILE *f = fopen(".minigit/HEAD", "r");
    if (!f) return NULL;
    fgets(ref, sizeof(ref), f);
    fclose(f);
    if (strncmp(ref, "ref: ", 5) == 0) {
        memmove(ref, ref + 5, strlen(ref) - 4);
        ref[strlen(ref)-1] = '\0';
        return ref;
    }
    return NULL;
}

char *get_ref_hash(const char *ref) {
    static char hash[9];
    char path[MAX_FILENAME];
    snprintf(path, sizeof(path), ".minigit/%s", ref);
    FILE *f = fopen(path, "r");
    if (!f) return NULL;
    fgets(hash, sizeof(hash), f);
    fclose(f);
    hash[8] = '\0';
    return hash;
}

void set_ref(const char *ref, const char *hash) {
    char path[MAX_FILENAME];
    snprintf(path, sizeof(path), ".minigit/%s", ref);
    FILE *f = fopen(path, "w");
    fprintf(f, "%s\n", hash);
    fclose(f);
}

void add_file(const char *filename) {
    if (!file_exists(filename)) {
        fprintf(stderr, "error: %s did not match any file(s) known to minigit\n", filename);
        return;
    }
    FileEntry files[MAX_FILES];
    int count;
    read_index(files, &count);
    // Check if already in index
    for (int i = 0; i < count; i++) {
        if (strcmp(files[i].name, filename) == 0) {
            return; // already added
        }
    }
    // Add to index
    strncpy(files[count].name, filename, MAX_FILENAME);
    // Compute hash of file contents
    FILE *f = fopen(filename, "r");
    if (!f) return;
    char content[10240];
    size_t n = fread(content, 1, sizeof(content), f);
    fclose(f);
    content[n] = '\0';
    compute_hash(content, files[count].hash);
    count++;
    write_index(files, count);
}

void add_files(int argc, char *argv[]) {
    for (int i = 2; i < argc; i++) {
        add_file(argv[i]);
    }
}

void create_object(const char *hash, const char *content) {
    char path[MAX_FILENAME];
    get_object_path(hash, path);
    char dir[MAX_FILENAME];
    snprintf(dir, sizeof(dir), ".minigit/objects/%.2s", hash);
    create_dir_if_not_exists(dir);
    FILE *f = fopen(path, "w");
    fwrite(content, 1, strlen(content), f);
    fclose(f);
}

void read_object(const char *hash, char *content, size_t max_size) {
    char path[MAX_FILENAME];
    get_object_path(hash, path);
    FILE *f = fopen(path, "r");
    if (!f) {
        content[0] = '\0';
        return;
    }
    size_t n = fread(content, 1, max_size - 1, f);
    content[n] = '\0';
    fclose(f);
}

void commit_files(const char *message) {
    FileEntry index_files[MAX_FILES];
    int index_count;
    read_index(index_files, &index_count);
    if (index_count == 0) {
        fprintf(stderr, "error: your index is empty\n");
        return;
    }
    // Create new commit
    Commit commit;
    // Generate commit hash
    char buf[2048];
    snprintf(buf, sizeof(buf), "%ld%s", (long)time(NULL), message);
    compute_hash(buf, commit.commit_hash);
    // Get parent commit
    char *ref = get_head_ref();
    char *parent_hash = get_ref_hash(ref);
    if (parent_hash) {
        strncpy(commit.prev_commit_hash, parent_hash, 8);
    } else {
        strcpy(commit.prev_commit_hash, "00000000");
    }
    // Timestamp
    snprintf(commit.timestamp, sizeof(commit.timestamp), "%ld", (long)time(NULL));
    strncpy(commit.message, message, MAX_COMMIT_MSG);
    // Copy files from index
    commit.file_count = index_count;
    for (int i = 0; i < index_count; i++) {
        commit.files[i] = index_files[i];
        // Copy file to object store
        char content[10240];
        FILE *f = fopen(index_files[i].name, "r");
        size_t n = fread(content, 1, sizeof(content), f);
        fclose(f);
        content[n] = '\0';
        create_object(index_files[i].hash, content);
    }
    // Write commit
    write_commit(&commit);
    // Update ref
    set_ref(ref, commit.commit_hash);
    printf("[%s] %s\n", ref + strlen("refs/heads/"), commit.commit_hash);
}

void print_log() {
    char *ref = get_head_ref();
    char *hash = get_ref_hash(ref);
    if (!hash) {
        fprintf(stderr, "error: your current branch 'master' does not have any commits yet\n");
        return;
    }
    while (hash && strcmp(hash, "00000000") != 0) {
        Commit commit;
        read_commit(hash, &commit);
        printf("commit %s\n", hash);
        printf("Date: %s\n", commit.timestamp);
        printf("    %s\n", commit.message);
        hash = commit.prev_commit_hash;
        if (hash && strcmp(hash, "00000000") != 0) {
            printf("\n");
        }
    }
}

void write_file_from_object(const char *hash, const char *filename) {
    char content[10240];
    read_object(hash, content, sizeof(content));
    FILE *f = fopen(filename, "w");
    fwrite(content, 1, strlen(content), f);
    fclose(f);
}

void checkout_commit(const char *hash) {
    char *ref = get_head_ref();
    char *current_hash = get_ref_hash(ref);
    if (!hash) {
        // Detach HEAD to this commit
        FILE *f = fopen(".minigit/HEAD", "w");
        fprintf(f, "%s\n", hash);
        fclose(f);
    } else {
        // Move branch
        set_ref(ref, hash);
    }
    // Read commit
    Commit commit;
    read_commit(hash, &commit);
    // Update index
    write_index(commit.files, commit.file_count);
    // Update working tree
    for (int i = 0; i < commit.file_count; i++) {
        write_file_from_object(commit.files[i].hash, commit.files[i].name);
    }
}

void reset_commit(const char *hash) {
    char *ref = get_head_ref();
    char *current_hash = get_ref_hash(ref);
    // Move branch
    set_ref(ref, hash);
    // Read commit
    Commit commit;
    read_commit(hash, &commit);
    // Update index
    write_index(commit.files, commit.file_count);
}

int main(int argc, char *argv[]) {
    if (argc < 2) {
        fprintf(stderr, "usage: %s <command> [<args>]\n", argv[0]);
        return 1;
    }

    if (strcmp(argv[1], "init") == 0) {
        init_repo();
        return 0;
    }

    if (!file_exists(".minigit")) {
        fprintf(stderr, "error: not a minigit repository\n");
        return 1;
    }

    if (strcmp(argv[1], "add") == 0) {
        if (argc < 3) {
            fprintf(stderr, "error: nothing to add\n");
            return 1;
        }
        add_files(argc, argv);
    } else if (strcmp(argv[1], "commit") == 0) {
        if (argc < 3) {
            fprintf(stderr, "error: no commit message\n");
            return 1
        }
        commit_files(argv[2]);
    } else if (strcmp(argv[1], "log") == 0) {
        print_log();
    } else if (strcmp(argv[1], "checkout") == 0) {
        if (argc < 3) {
            fprintf(stderr, "error: no commit hash\n");
            return 1;
        }
        checkout_commit(argv[2]);
    } else if (strcmp(argv[1], "reset") == 0) {
        if (argc < 3) {
            fprintf(stderr, "error: no commit hash\n");
            return 1;
        }
        reset_commit(argv[2]);
    } else {
        fprintf(stderr, "error: unknown command %s\n", argv[1]);
        return 1;
    }

    return 0;
}
